// // This module is designed to capture the input on the falling edge of the clock and output the captured value asynchronously.
module DFlipFlop (
    input wire clk,
    input wire reset,
    input wire D,
    output reg Q
);
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            Q <= 0;
        end else begin
            Q <= D;
        end
    end
endmodule
